SELECT conflict_type
FROM conflict_logs
WHERE resolution_status = 'unresolved';

SELECT report_summary
FROM usage_reports
WHERE package_id = 1;

SELECT interaction_type, interaction_details
FROM package_interactions
WHERE package_id = 1;

SELECT COUNT(required_package_id) AS required_package_count
FROM required_packages
WHERE package_id = 0;

SELECT method_name
FROM imported_methods
WHERE last_updated >= '2023-10-01 00:00:00';

SELECT interaction_type
FROM package_interactions
WHERE interaction_type = 'import';

SELECT COUNT(*) AS number_of_recent_packages
FROM imported_packages
WHERE last_updated > '2023-10-01';

SELECT imported_package_name, last_updated
FROM imported_packages
ORDER BY last_updated DESC;

SELECT COUNT(*) AS unresolved_conflicts
FROM conflict_logs
WHERE package_id = 0 AND resolution_status = 'unresolved';

SELECT required_package_name, version
FROM required_packages
WHERE package_id = 1;

SELECT report_summary
FROM usage_reports
WHERE report_id = 1;

SELECT package_name
FROM parent_packages
ORDER BY package_name;

SELECT imported_package_name, version
FROM imported_packages
WHERE last_updated > '2023-10-01 12:00:00';

SELECT package_name, last_updated
FROM parent_packages
WHERE package_id = 1;

SELECT imported_package_name, version
FROM imported_packages
ORDER BY last_updated DESC;

SELECT class_name, description
FROM imported_classes
WHERE last_updated = '2023-10-01 12:00:00';
